var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"당신이었군요.","JPN":"あなただったんですね。","ENG":"It’s you.","TWN":"原來是你。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"어떻게 침식체를 조종하는지 모르겠지만, 이제 그만두시죠.","JPN":"どうやって侵食体を操っているのかわかりませんが、もう諦めてください。","ENG":"I don’t know how you’re controlling the C.O.s, but you should stop now.","TWN":"雖然不清楚你是怎麼控制侵蝕體的，但請你收手吧。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"이 이상, 주인님의 휴가를 방해하게 두지는 않겠습니다. ","JPN":"これ以上、ご主人様の休みを邪魔するのは見過ごせません。","ENG":"I won’t let you ruin my Master’s vacation.","TWN":"我不允許你再打擾主人的假期。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"크윽……!!","JPN":"くうっ……！！","ENG":"Hngh!!","TWN":"唔……！！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L9_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"마, 말도 안 돼……!","JPN":"う、うそでしょ……！！","ENG":"Th-that's impossible!","TWN":"這…這怎麼可能……！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"어떻게 카운터도 아닌 일반인이 혼자 침식체들을 제압하는 거야?","JPN":"どうしてカウンターでもない一般人が、一人で侵食体を制圧できるの？","ENG":"You’re not a Counter. How are you fighting all these C.O.s?","TWN":"一個普通人怎麼可能獨自打倒侵蝕體？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"게다가 그런 파렴치한 복장으로……!","JPN":"しかもそんな恥知らずな服装で……！","ENG":"You’re even wearing that shameless outfit!","TWN":"而且還穿著那麼不要臉的衣服……！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"이 옷은 주인님이 선물해 주신 소중한 드레스입니다.","JPN":"この服はご主人様がプレゼントしてくださった大切なドレスです。","ENG":"This is a precious gift from my Master.","TWN":"這件珍貴的洋裝是主人送給我的禮物。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"그 이상의 무례한 언동은 삼가시길.","JPN":"それ以上の無礼な言動はご遠慮ください。","ENG":"Please stop insulting it.","TWN":"說話請放尊重一點。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"주인님? 소중한 드레스……?","JPN":"ご主人様？　大切なドレス……？","ENG":"Your Master? A precious gift?","TWN":"主人？珍貴的裙子……"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그 말은…… 역시 당신이 선배님의 애인이란 거군요?","JPN":"ということは……やっぱりあなたが先輩の恋人ってことですね？","ENG":"So you really are his lover... aren’t you?","TWN":"意思是……你果然是前輩的情人囉？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"... I beg your pardon?","TWN":"……嗯？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"시치미 뗄 생각 하지 마!!","JPN":"とぼけるな！","ENG":"Stop playing the fool!","TWN":"少給我裝蒜！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"늘 이런 식이야.","JPN":"いつもこうだ。","ENG":"It’s been always like this.","TWN":"每次都這樣！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"내가 좋아하는 사람은 나를 좋아하지 않았어.","JPN":"私が好きな人は私のこと好きじゃないんだ。","ENG":"When I love someone, they never love me back.","TWN":"我喜歡的人不喜歡我！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그래서 달라지려고 노력도 해 봤지만, 결국 쓸데없는 짓이었다고.","JPN":"それで変わろうと努力もしてみたけど、結局無駄なことだった。","ENG":"I tried to change, but it never worked.","TWN":"就算我很努力改變，到頭來還是白忙一場！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그렇게 좌절한 날 격려해 준 사람은 선배님뿐이었는데……!","JPN":"挫折している私を励ましてくれたのは先輩だけだったのに……！","ENG":"Dark was the only one who helped me when I was down!","TWN":"在我最挫折的時候，只有前輩鼓勵我……！"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"이 복장 때문에 뭔가 오해를 하고 계신 모양이군요.","JPN":"この服装のせいで何か誤解されているようですね。","ENG":"I believe this dress misled you.","TWN":"你好像因為我這身造型而有所誤會。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"시간을 주시면 이해하실 수 있게 설명해 드리겠습니다.","JPN":"時間をいただければ理解できるように説明いたします。","ENG":"Please give me a moment to explain.","TWN":"你可以給我點時間跟你解釋解釋嗎？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"당신 같은 사람한테 동정 받고 싶지 않아!","JPN":"あなたみたいな人に同情されたくない！","ENG":"I don’t need your sympathy!","TWN":"我才不需要你的同情！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"온실에서 자란 것처럼 잘난 사람이 어떻게 내 마음을 이해하겠어!","JPN":"温室育ちみたいな人間が、私の気持を理解できるはずがない！","ENG":"Your life must have been a bed or roses. You will never understand me!","TWN":"像你這種溫室裡的花朵怎麼可能懂我的心情！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"그래요. 저는 한때 온실에서 가꿔진 존재였죠.","JPN":"そうです。私は昔、温室で育てられた存在でした。","ENG":"Yes, I once was a flower tended by a gardener.","TWN":"沒錯，我是曾經被種在溫室裡。"},"stage":{"bg":"SS_MAID_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"그렇지만 그 시절은, 말씀하신 것처럼 아름답지는 않은 시절이었습니다.","JPN":"けれどもあの時代は、おっしゃるような美しいものではありませんでした。","ENG":"But it was not the happiest time of my life, to be honest.","TWN":"但並非如你所說，那是我人生中最不開心的時候。"},"stage":{"bg":"SS_MAID_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"제가 가꿔진 까닭은……. 사람을 솎아내기 위해서였으니까요.","JPN":"私が育てられた理由は……人を間引くためだったからです。","ENG":"They tended me... so that they could pluck out other people.","TWN":"因為我的存在……為的是要把人除掉。"},"stage":{"bg":"SS_MAID_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"사람을……?","JPN":"人を……？","ENG":"People?","TWN":"把人除掉……？"},"stage":{"bg":"SS_MAID_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"네. 그것이 자의였든, 타의였든 이 손에 수많은 피를 묻혔지요.","JPN":"はい。それが自分の意思であれ、他人の意思であれ、この手は数多くの血に染められたものです。","ENG":"Yes. Whether it was by my will or not, I took countless lives with my hands.","TWN":"是的，不管是不是出於我的意願，這雙手都沾滿了鮮血。"},"stage":{"bg":"SS_MAID_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"그 굴레에서 벗어날 수 있게 도와 준 분이, 바로 주인님이십니다.","JPN":"そのしがらみから抜け出せるように助けてくださった方が、ご主人様です。","ENG":"But the Master helped me to leave all that behind and start a new life.","TWN":"而將我從那個牢籠裡解救出來的人，就是主人。"},"stage":{"bg":"SS_MAID_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"서, 선배님이……?","JPN":"せ、先輩が……？","ENG":"D-Dark did that?","TWN":"前輩嗎……？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"네. 그렇기 때문에, 저는 주인님의 애인처럼 분에 넘치는 영광을 받을 자격이 없습니다.","JPN":"はい。ですから、私にはご主人様の恋人という身に余る光栄を受ける資格がありません。","ENG":"Yes. Therefore, I don’t deserve to be his lover.","TWN":"沒錯。主人是我的救命恩人，我哪有資格當他的情人。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"제가 할 수 있는 일은 그저 메이드로서, 주인님의 뜻을 따를 뿐.","JPN":"私にできることはただメイドとして、主の意に従うだけ。","ENG":"All I can do is to follow him as his maid.","TWN":"我能做的，就只是作為一位女僕，100%服從主人的命令。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"자, 잠깐…… 메이드라고요? 애인이 아니라?","JPN":"ちょ、ちょっと待って……メイドですって？　恋人じゃなくて？","ENG":"Wait... You’re Dark’s maid, not his lover?","TWN":"等等……你說你是女僕？不是情人喔？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"거짓말!! 그럼 그 웨딩 드레스는 뭔데요!","JPN":"嘘！！　じゃあそのウェディングドレスはなに？","ENG":"You’re lying! Then why are you wearing that dress?","TWN":"你騙人～～～那你身上的婚紗是怎樣！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"이 지역에서 열리는 이벤트를 위한 복장일 뿐입니다.","JPN":"この地域で開催されるイベントのための服装です。","ENG":"This is a costume to participate in a local event.","TWN":"這是因為活動才穿的。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"주위를 살피셨다면, 웨딩 드레스를 입고 계신 분들을 보셨을 텐데요.","JPN":"周りを見渡せば、ウェディングドレスを着ている方が大勢いることをご覧になったと思います。","ENG":"You must have noticed other people wearing dresses, if you have looked around.","TWN":"你看一下周圍，應該有很多跟我一樣穿婚紗的人吧？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그러고 보니……. 그때 로자리아 님도 웨딩 드레스를…….","JPN":"そういえば……あの時ロザリアさんもウェディングドレスを……","ENG":"Now that you mention it... Rosaria was wearing a wedding dress too...","TWN":"這麼說來……那時候羅莎莉亞好像也穿著婚紗……"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"주인님께 하고 싶은 말씀이 있으시다면, 안내해 드리겠습니다.","JPN":"ご主人様に申し上げたいことがあるのなら、ご案内いたします。","ENG":"If you wish to speak to my Master, let me show you the way.","TWN":"你有話要跟主人說嗎？我可以帶你去找他。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"다만, 행사를 방해한 대가는 치르시겠다는 조건 하에.","JPN":"ただし、イベントを邪魔した代価は払うという条件付きで。","ENG":"However, you have to pay for the disturbance you’ve caused.","TWN":"但你必須先針對破壞活動一事，付出應有的代價。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Gah!","TWN":"嗚……！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OGRE2_NPC_NULL_NULL","text":{"KOREA":"(……검은 머리 여자! 여긴 우리가 맡겠다!)","JPN":"(黒髪の女……！　ここは俺たちが引き受ける！)","ENG":"(... Black-haired female! We take it from here!)","TWN":"(……黑頭髮的女人！這裡交給我們！)"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OGRE1_NPC_NULL_NULL","text":{"KOREA":"(그녀의 행복! 지켜낸다! 반드시!)","JPN":"(彼女の幸せ！　守る！　必ず！)","ENG":"(Her happiness! We protect!)","TWN":"(她的幸福！由我來守護！放心！)"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"음? 이 침식체들, 설마 저 분을 지켜 주려고 하는 건가요?","JPN":"この侵食体たち、まさかあの方を守ろうとしているのですか？","ENG":"Hmm? Are those C.O.s trying to protect her?","TWN":"嗯？這些侵蝕體是想保護她嗎？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"다, 당신들……!","JPN":"あ、あなたたち……！","ENG":"Y-you guys!","TWN":"你…你們……！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"역시……. 나는 내 방식대로, 선배님한테 진심을 털어놓겠어.","JPN":"やっぱり……私は自分のやり方で、先輩に本音を伝える。","ENG":"I... I will tell Dak about my feelings, in my own way.","TWN":"沒錯……我要照我的方式向前輩吐露心意！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"각오해, 메이드! 선배님을 포기할 생각은 절대로 없으니까!","JPN":"覚悟しろ、メイド！　先輩を諦めるつもりは絶対ないから！","ENG":"You’d better be prepared, maid! I’m never giving up Dark!","TWN":"覺悟吧，女僕！我是絕對不會放棄前輩的！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"……사건의 경과는 여기까지입니다.","JPN":"……事件の経過はここまでです。","ENG":"... And that’s how it went.","TWN":"……事情的經過就是這樣。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"혹시 지금까지 저의 이야기에서 용의자로 짐작가는 분이 있으신지요?","JPN":"今までの私の話を聞いて、容疑者に思い当たる方はいらっしゃいますか？","ENG":"Do you have any suspect you can think of from my story?","TWN":"從我的描述當中，主人有覺得誰很可能是嫌犯嗎？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"용의자는 주인님을 선배님이라고 불렀습니다만.","JPN":"容疑者はご主人様を先輩と呼んでいました。","ENG":"The woman called you Dark.","TWN":"嫌犯都稱呼主人為前輩。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"으음? 서, 선배님이라고?","JPN":"うむ？　せ、先輩と？","ENG":"H-huh? Dark?","TWN":"嗯？叫我前輩？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그, 글쎄? 난 잘 모르겠는데?","JPN":"さ、さあな。私は知らないな。","ENG":"I-I don’t know. That doesn’t ring a bell.","TWN":"沒印象呢？我也不太清楚。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"면목없습니다. 제가 방심하지만 않았어도 용의자를 놓치지 않았을 텐데…….","JPN":"面目ございません。私が油断しなかったら、容疑者を逃さなかったはず……","ENG":"I’m very ashamed. I could have caught her if I hadn’t let my guard down...","TWN":"都是我的錯，都怪我太大意才會讓嫌犯給逃掉……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"뭐, 딱히 상관없지 않나.","JPN":"まあまあ、いいじゃないか。","ENG":"It doesn’t matter.","TWN":"哎唷～不是你的問題啦～"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"베로니카 양 덕분에 비치 웨딩 콘테스트도 이렇게 무사히 열렸으니까.","JPN":"ベロニカのおかげで、ビーチウェディングコンテストもこうやって無事に開かれたから。","ENG":"The Beach Wedding Contest started without any problem, thanks to you.","TWN":"都是因為你，沙灘婚紗照比賽才能順利進行。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"과찬이십니다. 메이드로서 해야 할 일을 했을 뿐.","JPN":"身に余るお言葉です。メイドとして役目を果たしただけでございます。","ENG":"Thank you. I only did what I had to do as your maid.","TWN":"不敢當，這是我份內的事。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"그보다 소란을 수습하다 보니 촬영이 늦어졌군요.","JPN":"それより騒ぎのせいで、撮影が遅くなりましたね。","ENG":"Our photo shoot is running late.","TWN":"不過很抱歉，因為處理騷動而耽誤到拍照的時間。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"해가 지기 전에 사진을 찍어 주실 분을 섭외하겠습니다.","JPN":"日が暮れる前に写真を撮ってくださる方を探してきます。","ENG":"I’ll go find someone who will take pictures for us before the sunset.","TWN":"趁著太陽還沒下山，我趕快去找人來拍照。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아니, 괜찮네. 사진사는 처음부터 정해 뒀거든.","JPN":"いや、大丈夫だ。カメラマンは最初から決めておいたんだ。","ENG":"It’s okay. I already have the photographer.","TWN":"沒關係，不用了。攝影師一開始就決定好了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Pardon?","TWN":"是哪位呢？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"메이드장님! 저희 왔슴다!","JPN":"メイド長！　モネたちが来たっす！","ENG":"Chief Maid! We’re here, ma’am!","TWN":"女僕長大人！我來囉！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"흥, 이벤트 사진이란 거 꼭 우리까지 찍어야 돼?","JPN":"ふん、イベント写真なんか、私たちまで撮らないといけないの？","ENG":"Hmpf, why do we have to take pictures?","TWN":"哼，不過就是個活動照，非得要我們來拍不可嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"주인님께서 부탁하신 일입니다, 리코리스. 츤츤거리지 마세요.","JPN":"ご主人様の依頼です、リコリス。ツンツンしないでください。","ENG":"The Master asked us, Lycoris. Stop being a tsundere.","TWN":"這是主人的吩咐，莉克莉絲，你就不要再扭扭捏捏的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"모네랑 릴리, 리코리스까지…….","JPN":"モネとリリー、リコリスまで……","ENG":"Mone, Lily, and Lycoris...","TWN":"莫妮…莉莉…莉克莉絲……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"사진은 릴리 양에게 부탁해 두었네.","JPN":"写真はリリーに頼んでおいた。","ENG":"I asked Lily to take the photo.","TWN":"照片我拜託莉莉負責。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"원래 혼자보단 둘이, 둘보다는 셋이, 셋보다는 넷이 더 즐거운 법 아닌가.","JPN":"一人よりは二人、二人よりは三人、三人よりは四人の方が楽しいのではないか。","ENG":"It’s always more fun with more people, don’t you think?","TWN":"本來就是兩個人比一個人好，三個人比兩個人好，四個人比三個人好不是嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"그럼 주인님. 준비를 마치면 언제든 말씀해주시길.","JPN":"では、ご主人様。準備ができたら、いつでもおっしゃってください。","ENG":"Master, please let me know when you’re ready.","TWN":"主人，那你準備好就跟我說！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"분부대로 최고의 인생샷을 찍어 드리겠습니다.","JPN":"ご命令どおり、人生で最高の写真を撮って差し上げます。","ENG":"I’ll take the best shot of your life.","TWN":"我會照主人吩咐的，為您拍出人生中最棒的照片。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"주인님께서는……. 처음부터 이럴 요량이셨군요.","JPN":"ご主人様は、最初からこうするつもりで……","ENG":"You were... planning this all along.","TWN":"原來……主人從一開始就是這麼打算的嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"알겠습니다. 주인님께서 선물해 주신 추억, 저 역시 최고의 한 장으로 보답해 드리겠습니다.","JPN":"かしこまりました。ご主人様がプレゼントしてくださった思い出、私も最高の一枚でお返ししたいと思います。","ENG":"Thank you for everything you’ve prepared for me. I’ll do my best to repay you by taking the best shot of my life.","TWN":"好的，謝謝主人送我的回憶，我也會拍出最棒的照片來報答主人。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"앗! 그러고 보니 사진 찍을 때 쓸 소품들을 잔뜩 얻어 왔지 말임다!","JPN":"あっ！　そういえば写真を撮る時使う小物をいっぱいもらって来たっす！","ENG":"Oh! Come to think of it, we brought a lot of props for the photo shoot!","TWN":"對了！我有弄來很多拍照的配件喔！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"모네가 금방 가서 가져오겠슴다!!","JPN":"モネが今すぐ持ってくるっす！","ENG":"Mone will bring them right away, sir!","TWN":"等我一下，我去拿過來！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"야, 꼬맹이?! 앞 좀 보고 뛰어다녀!","JPN":"ちょっと、チビ！　前を見て走りなさいよ！","ENG":"Hey, kid! Watch your step!","TWN":"喂！看路啊小鬼！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"으와아아앗! 너, 넘어짐다!","JPN":"うおおおおっ！　こ、転んじゃうっす！","ENG":"Waaaa! I-I’m falling down!","TWN":"啊～～！跌倒了！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"죄, 죄성함다…….","JPN":"ご、ごめんなさいっす……","ENG":"I’m sorry, ma’am...","TWN":"對…對不起……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"다, 다치지 않았나? 베로니카 양?","JPN":"怪我はないか、ベロニカ？","ENG":"A-are you hurt, Veronica?","TWN":"貝洛妮卡，你沒受傷吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"……아, 네. 주인님께서 받아 주신 덕분에.","JPN":"……あ、ええ、ご主人様が受け止めてくださったおかげで。","ENG":"... No, all thanks to you, Master.","TWN":"……是的，我沒事，多虧主人接住我。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"지금 이 각도……. 의도치 않은 우연이 빚어낸 이 연출…….","JPN":"今のこの角度……思わぬ偶然が生み出したこの演出……","ENG":"This angle... and this unexpected pose...","TWN":"現在這個畫面……非常不經意的感覺……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"그리고 보기 드문 메이드장님의 저 표정까지.","JPN":"そして激レアなメイド長のあの表情まで。","ENG":"Plus that look on the Chief Maid’s face, that’s very rare to see...","TWN":"再加上女僕長難得的表情，"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"지금이야말로 절호의 셔터 찬스로군요.","JPN":"今こそ絶好のシャッターチャンスですね。","ENG":"Now is the moment to press the button!","TWN":"現在就是按下快門的最佳時機！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REVIEWER1_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>★★★★★</color> \\n새 신부의 수줍은 표정, 그에 대비되는 대범한 드레스. 그야말로 완벽한 연인.","JPN":"<color=#ffd34c>★★★★★</color>\\n花嫁のはにかむ表情、その割りにはとても大胆なドレス。まさに完璧な恋人。","ENG":"<color=#ffd34c>★★★★★</color> \\nA blushing bride in a very bold dress. A woman of your dream.","TWN":"<color=#ffd34c>★★★★★</color> \\n新娘嬌羞的表情，還有與新娘的表情成對比的大膽婚紗，這就是完美Couple！"},"stage":{"bg":"SUMMER2_03","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REVIEWER2_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>★★★★★</color> \\n결혼은 미친 짓일지도 모른다. 그러나 사진 속 이 분과 함께라면 괜찮을지도…….","JPN":"<color=#ffd34c>★★★★★</color>\\n結婚は狂気の沙汰かもしれない。しかし写真の中のこの方と一緒なら大丈夫かも……","ENG":"<color=#ffd34c>★★★★★</color> \\nMarriage is madness. But with her, maybe everything will be okay...","TWN":"<color=#ffd34c>★★★★★</color> \\n俗話婚姻是愛情的墳墓，但我願意和照片裡的人一起進墳墓……"},"stage":{"bg":"SUMMER2_03","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REVIEWER3_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>★★★★☆</color> \\n신부 측은 완벽. 그러나 로봇의 메타포는 의미 불명.","JPN":"<color=#ffd34c>★★★★☆</color>\\n花嫁側は完璧だ。しかしロボットのメタファーは意味不明。","ENG":"<color=#ffd34c>★★★★☆</color> \\nThe bride is perfect. But I don’t understand why a robot is here.","TWN":"<color=#ffd34c>★★★★☆</color> \\n新娘的部分完美！只是不太明白機器人的用意何在？"},"stage":{"bg":"SUMMER2_03","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"이……! 이이……!","JPN":"この……この……！","ENG":"You... You...","TWN":"唔……！可惡……！"},"stage":{"bg":"SUMMER2_03","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"이 불여우 같은 것이……!!","JPN":"この女狐が……！！","ENG":"You vixen!","TWN":"那個狐狸精……！！"},"stage":{"bg":"SUMMER2_03","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그럴싸한 거짓말로 나를 속여??","JPN":"私を騙したってこと？","ENG":"You lied to me!","TWN":"說起謊來臉不紅氣不喘！"},"stage":{"bg":"SUMMER2_03","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그래, 이렇게 된 이상…… 나도 선배님의 마음을 사로잡기 위한 <color=#ffd34c>비장의 레시피</color>를……!!","JPN":"そうだ、こうなったからには……私も先輩の心をつかむための<color=#ffd34c>とっておきのレシピ</color>を……！！","ENG":"Okay, then... I’ll have to bring out the <color=#ffd34c>best recipe</color> for Dark!","TWN":"很好！既然如此……我也要拿出<color=#ffd34c>秘方</color>來偷走前輩的心……！！"},"stage":{"bg":"SUMMER2_03","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"후훗. 역시 삼각관계 로맨스에는 엎치락뒤치락하는 재미가 있어야지.","JPN":"ふふ、やはり三角関係ロマンスは二転三転する展開が楽しいものじゃな。","ENG":"Hah hah, what’s a romance without a love triangle?","TWN":"呵呵，這種灑狗血的三角戀果然很精采呢～"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_SEAWAVE"},{"id":"L36_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"과연 마지막에 미소 짓는 신부는 누가 되려나?","JPN":"はて、最後に笑顔になれる花嫁は誰になるかのう。","ENG":"I wonder who will be the real bride in the end.","TWN":"究竟是命運的安排，還是情感的糾葛，最後誰能笑著成為新娘呢？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"응? 신부……!?","JPN":"ん？　花嫁……！？","ENG":"Huh? Bride?!","TWN":"嗯？新娘……！？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"맞다! 깜빡했잖아, 콘테스트 수상 심사평!","JPN":"しまった！　忘れておったわ、コンテストの受賞審査評価！","ENG":"Oh! I forgot! The contest commentary!","TWN":"啊！我都忘了！比賽講評！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"뭐, 기껏해야 필멸자들끼리의 도토리 키재기 승부인데. 당연히 우월한 이 몸의 압승이겠지만.","JPN":"まあ、せいぜい定命の者同士のどんぐりの背比べ勝負じゃ。当然優れた妾の圧勝じゃろうが。","ENG":"Well, it’s just a pathetic contest between mortals. It’s obvious that I’m the winner here.","TWN":"哼，其他都是些阿貓阿狗的，一定是我獲得壓倒性的勝利吧！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"어디보자…….","JPN":"どれどれ……","ENG":"Let’s see...","TWN":"我來看看……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>우아하고 고고한 매력. 어린이 모델로는 수준급.</color>","JPN":"<color=#ffd34c>エレガントで孤高の魅力。子役モデルとしてはかなりのレベル。</color>","ENG":"<color=#ffd34c>Elegant and aloof. Such charm for a child.</color>","TWN":"<color=#ffd34c>優雅的冰山美人，以兒童組來說有超水準的表現。</color>"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L42_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>모델은 아름다우나, 혼자 찍은 사진 뿐. 콘테스트의 취지를 전혀 이해하지 못함.</color>","JPN":"<color=#ffd34c>モデルは美しいが、一人で撮った写真だけ。コンテストの趣旨をまったく理解していない。</color>","ENG":"<color=#ffd34c>The model looks beautiful, but she’s all alone in the pictures. It looks like she didn’t understand the concept of this event.</color>","TWN":"<color=#ffd34c>新娘很漂亮，只是照片中沒看到新郎，完全沒抓到比賽的重點。</color>"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>힘냈다, 2등!! 내년에도 분발하자!!</color>","JPN":"<color=#ffd34c>頑張った、2等！　来年も頑張ろう！</color>","ENG":"<color=#ffd34c>Good job, you’re in second place! I’ll see you next year!</color>","TWN":"<color=#ffd34c>第2名加油！！明年再接再厲！</color>"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"으으……!! 이 어리석은 필멸자들 주제에 감히 나를 평가해?!","JPN":"うぅ……！！　愚かな定命の者どもの分際で、この妾を評価するじゃと！？","ENG":"Aww... You foolish mortals dare judge me!","TWN":"呃……！！這些愚蠢的東西！憑什麼對我品頭論足的！！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"이 따위 심사평을 써내린 무례한 필멸자들을…… 당장 내 앞에 끌고 와서……!!","JPN":"こんな審査評価を書きやがった無礼な定命の者どもを……今すぐ妾の前に連れてくるのじゃ……！！","ENG":"I’m going to drag these insolent whelps before me and—","TWN":"立刻把寫下這些評語的傢伙……帶到我面前……！！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"응? 이건 또 무슨 소리야?","JPN":"うん？　これはなんの音じゃ？","ENG":"Huh? What’s that noise?","TWN":"嗯？這又是什麼聲音？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_33"},{"id":"L48_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>손상 부위── 수리 불──가.</color>","JPN":"<color=#ff3636>損傷部位── 修理不──可。</color>","ENG":"<color=#ff3636>Damage... beyond repair...</color>","TWN":"<color=#ff3636>毀損位置──無法修──復</color>"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L49_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>교전 속행 ───────가능.</color>","JPN":"<color=#ff3636>交戦続行 ───────可能。</color>","ENG":"<color=#ff3636>Engaging...</color>","TWN":"<color=#ff3636>可繼續───────交戰</color>"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_START_BIG"},{"id":"L50_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>모든 유기체를…….</color>","JPN":"<color=#ff3636>すべての有機体を……</color>","ENG":"<color=#ff3636>Destroy... every organic being...</color>","TWN":"<color=#ff3636>將所有生物……</color>"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"넌 또 뭐야?! 시끄럽게!","JPN":"其方は何者じゃ！？　うるさいのう！","ENG":"What the heck is this?! SHUT UP!","TWN":"吵死了！你又是什麼東西啦！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"씨이……. 진짜…….","JPN":"ちっ……まったく……","ENG":"Sheesh...","TWN":"討厭……硬要惹我生氣……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"시종! 어디 있느냐! 시종!!","JPN":"僕よ！　どこにおる、僕！！","ENG":"Servant! Where are you? Servant!","TWN":"來人！來人啊！！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"당장 이 세상에서 가장 화려한 드레스랑 신랑감을 가져 와! 어서!","JPN":"今すぐこの世で一番華やかなドレスと新郎を連れて来るのじゃ！　早く！","ENG":"Bring me the most elegant dress and a groom, right now!","TWN":"立刻把世界上最奢華的婚紗，和最帥的新郎給我帶來！馬上！！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};